def gen(rng, size):
    n = min(size, 50)
    # Build a valid sequence: ensure leaves never exceed enters
    chars = []
    in_room = 0
    for _ in range(n):
        if in_room == 0:
            chars.append('E')
            in_room += 1
        elif in_room >= n - len(chars):
            chars.append('L')
            in_room -= 1
        else:
            if rng.random() < 0.6:
                chars.append('E')
                in_room += 1
            else:
                chars.append('L')
                in_room -= 1
    return [''.join(chars)]

